// Парсим оба CSV и формируем prompt для Claude.
const garminCsv = $('Тянем Garmin CSV').item.json.data || $('Тянем Garmin CSV').item.json;
const eventsCsv = $('Тянем события дня').item.json.data || $('Тянем события дня').item.json;

// Универсальный split на "строки CSV" (без учёта экранирования, пока хватает).
function parseCsv(raw) {
  if (typeof raw !== 'string') raw = String(raw);
  const lines = raw.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];
  const splitLine = (s) => s.match(/("([^"]|"")*"|[^,]*)(,|$)/g)
    .filter(Boolean)
    .map(v => v.replace(/,$/, '').replace(/^"|"$/g, '').replace(/""/g, '"').trim());
  const headers = splitLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = splitLine(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = cells[i] ?? ''; });
    return obj;
  });
}

const garminRows = parseCsv(garminCsv);
const eventsRows = parseCsv(eventsCsv);

// Последняя строка Garmin = вчерашние метрики
const latest = garminRows[garminRows.length - 1] || {};

// Предыдущая неделя для контекста
const week = garminRows.slice(-7);
const avg = (key) => {
  const nums = week.map(r => parseFloat(r[key])).filter(v => !isNaN(v));
  if (!nums.length) return null;
  return (nums.reduce((a, b) => a + b, 0) / nums.length).toFixed(1);
};

// События на сегодня
const today = new Date().toISOString().slice(0, 10);
const todayEvents = eventsRows.filter(e => (e.date || e.Date || '').startsWith(today));

const payload = {
  today,
  latest,
  week_averages: {
    sleep_hours: avg('sleep_hours'),
    sleep_score: avg('sleep_score'),
    hrv_last_night: avg('hrv_last_night'),
    steps: avg('steps'),
    stress_avg: avg('stress_avg'),
  },
  events: todayEvents.map(e => ({
    title: e.title || e.summary || e.Title || '',
    start: e.start || e.start_time || e.time || '',
  })),
};

return [{ json: payload }];
